def graceful_shutdown
      if @status != :restart
        @binder.close
      end

      @thread_pool.shutdown(options[:force_shutdown_after])
    end

def reject!(classes) # :nodoc:
        if @excluded_descendants
          classes.reject! { |d| @excluded_descendants.include?(d) }
        end
        classes
      end

def include_new_modules(modules)
        return if modules.empty?

        modules.each { |mod| make_inclusion(mod) }
      end

def include_block(block)
        return unless block

        mod = Module.new
        make_inclusion(mod) { mod.class_eval(&block) }
      end

def clean_with(*args)
      Safeguard.new.run
      values.each { |cleaner| cleaner.clean_with(*args) }
    end

def wakeup!(client)
      if @block.call client
        @selector.deregister client.to_io
        @reactor_size -= 1
        @timeouts.delete client
      end
    end

def phased_restart(refork = false)
      return false if @options[:preload_app] && !refork

      @pending_phased_restart = refork ? :refork : true
      wakeup!

      true
    end

def close
      return if @closed
      @closed = true
      begin
        @body.close if @body.respond_to?(:close)
      ensure
        @block.call
      end

def initialize(status: nil, message: nil, headers: nil)
        super(message)

        @status  = status
        @headers = headers
      end

def publish(name, *args)
        notifier.publish(name, *args)
      end

      def publish_event(event) # :nodoc:
        notifier.publish_event(event)
      end

def add(client)
      @input << client
      @selector.wakeup
      true
    rescue ClosedQueueError, IOError # Ignore if selector is already closed
      false
    end

def register(client)
      @selector.register(client.to_io, :r).value = client
      @reactor_size += 1
      @reactor_max = @reactor_size if @reactor_max < @reactor_size
      @timeouts << client
    rescue ArgumentError
      # unreadable clients raise error when processed by NIO
    end

def shutdown
      @input.close
      begin
        @selector.wakeup
      rescue IOError # Ignore if selector is already closed
      end
      @thread&.join
    end

def []=(k, v)
        canonical = k.downcase
        delete k if @names[canonical] && @names[canonical] != k # .delete is expensive, don't invoke it unless necessary
        @names[k] = @names[canonical] = k
        super k, v
      end

def socket_activation_fd(int)
      int + 3 # 3 is the magic number you add to follow the SA protocol
